const raw = $input.first().json;
const body = raw.body !== undefined ? raw.body : raw;
const keys = body && typeof body === 'object' ? Object.keys(body) : [];
const flowKey = (body.flowKey || body.key || body.flow || body.id || body.metric || 'net-anomaly').toString();
const topic = 'net-anomaly-' + flowKey.replace(/[^a-zA-Z0-9._-]+/g, '-').slice(0, 60);
const stream = (typeof process !== 'undefined' && process.env && process.env.ZULIP_SFLOW_STREAM) ? process.env.ZULIP_SFLOW_STREAM : 'network';
let md = '**sFlow / network anomaly**\n';
md += '**flowKey:** ' + flowKey + '\n';
if (body.threshold !== undefined) md += '**threshold:** ' + body.threshold + '\n';
if (body.value !== undefined) md += '**value:** ' + body.value + '\n';
if (body.message) md += (body.message || '').toString() + '\n';
if (keys.length && !body.message) md += '```json\n' + JSON.stringify(body, null, 2).slice(0, 3500) + '\n```\n';
return [{ json: { zulip_stream: stream, zulip_topic: topic, zulip_content: md, flowKey: flowKey, result: 'parsed' } }];
